import React, { useEffect, useState } from "react";
import axios from "axios";
import "./studentDashboard.css";

export default function StudentDashboard() {
  const [activeTab, setActiveTab] = useState("overview");
  const [student, setStudent] = useState({});
  const [mentor, setMentor] = useState(null);
  const [meetings, setMeetings] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [reports, setReports] = useState([]);
  const [mentors, setMentors] = useState([]);
  const [selectedSlot, setSelectedSlot] = useState("");
  const [selectedFile, setSelectedFile] = useState(null);
  const [projectData, setProjectData] = useState({
    mentor_id: "",
    project_title: "",
    description: "",
    domain: "",
    time_required: "",
    skills_required: "",
  });

  const studentId = localStorage.getItem("userId");

  // Fetch student info
  useEffect(() => {
    const fetchData = async () => {
      try {
        const studentRes = await axios.get(`/api/student/${studentId}`);
        setStudent(studentRes.data);

        if (studentRes.data.mentor_id) {
          const mentorRes = await axios.get(`/api/mentors/${studentRes.data.mentor_id}`);
          setMentor(mentorRes.data);
        }

        const meetingRes = await axios.get(`/api/meetings/${studentId}`);
        setMeetings(meetingRes.data);

        const reportRes = await axios.get(`/api/reports/${studentId}`);
        setReports(reportRes.data);

        const mentorList = await axios.get("/api/mentors");
        setMentors(mentorList.data);
      } catch (err) {
        console.error("Error fetching student data:", err);
      }
    };
    fetchData();
  }, [studentId]);

  // Fetch mentor availability
  useEffect(() => {
    const fetchAvailability = async () => {
      if (mentor && mentor.sno) {
        const res = await axios.get(`/api/availability/${mentor.sno}`);
        setAvailability(res.data);
      }
    };
    fetchAvailability();
  }, [mentor]);

  const handleSlotBooking = async () => {
    if (!selectedSlot) return alert("Please select a time slot.");
    try {
      await axios.post("/api/meetings", {
        student_id: studentId,
        mentor_id: mentor.sno,
        meeting_date: selectedSlot.split(" ")[0],
        meeting_time: selectedSlot.split(" ")[1],
        topic: "Mentor Session",
        location: "College",
      });
      alert("Meeting booked successfully!");
    } catch (err) {
      console.error(err);
      alert("Error booking meeting");
    }
  };

  const handleReportUpload = async (e) => {
    e.preventDefault();
    if (!selectedFile) return alert("Please select a file first.");

    const formData = new FormData();
    formData.append("file", selectedFile);
    formData.append("student_id", studentId);
    formData.append("mentor_id", mentor ? mentor.sno : null);
    formData.append("title", selectedFile.name);

    try {
      await axios.post("/api/reports", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      alert("Report uploaded successfully!");
    } catch (err) {
      console.error(err);
      alert("Error uploading report");
    }
  };

  const handleProjectChange = (e) => {
    setProjectData({ ...projectData, [e.target.name]: e.target.value });
  };

  const handleProjectSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("/api/mentor-requests", {
        ...projectData,
        student_id: studentId,
      });
      alert("Project request submitted successfully!");
    } catch (err) {
      console.error(err);
      alert("Error submitting project request");
    }
  };

  return (
    <div className="student-dashboard">
      <h1>Student Dashboard</h1>

      <div className="tab-buttons">
        <button
          className={activeTab === "overview" ? "active" : ""}
          onClick={() => setActiveTab("overview")}
        >
          Overview
        </button>
        <button
          className={activeTab === "mentors" ? "active" : ""}
          onClick={() => setActiveTab("mentors")}
        >
          Mentors
        </button>
        <button
          className={activeTab === "project" ? "active" : ""}
          onClick={() => setActiveTab("project")}
        >
          Project
        </button>
      </div>

      {/* OVERVIEW TAB */}
      {activeTab === "overview" && (
        <div className="overview-tab">
          <h2>Hello, {student.name ? student.name : "Student"} 👋</h2>
          <p>
            <strong>Mentor:</strong>{" "}
            {mentor ? mentor.facultyname : "Not assigned yet"}
          </p>

          <div className="overview-sections">
            {/* Meetings */}
            <div className="section-card">
              <h3>Upcoming Meetings</h3>
              {meetings.length === 0 ? (
                <p>No upcoming meetings</p>
              ) : (
                meetings.map((m) => (
                  <p key={m.id}>
                    {m.meeting_date} at {m.meeting_time} — {m.topic}
                  </p>
                ))
              )}

              {mentor && (
                <>
                  <h4>Book a Slot</h4>
                  <select
                    value={selectedSlot}
                    onChange={(e) => setSelectedSlot(e.target.value)}
                  >
                    <option value="">Select slot</option>
                    {availability.map((a) => (
                      <option
                        key={a.id}
                        value={`${a.day} ${a.start_time}`}
                      >{`${a.day} ${a.start_time} - ${a.end_time}`}</option>
                    ))}
                  </select>
                  <button onClick={handleSlotBooking}>Book Meeting</button>
                </>
              )}
            </div>

            {/* Reports */}
            <div className="section-card">
              <h3>Reports</h3>
              <form onSubmit={handleReportUpload}>
                <input
                  type="file"
                  onChange={(e) => setSelectedFile(e.target.files[0])}
                />
                <button type="submit">Upload Report</button>
              </form>
              <h4>Uploaded Reports</h4>
              {reports.length === 0 ? (
                <p>No reports uploaded yet</p>
              ) : (
                <ul>
                  {reports.map((r) => (
                    <li key={r.id}>
                      {r.title} — {r.status}
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      )}

      {/* MENTORS TAB */}
      {activeTab === "mentors" && (
        <div className="mentors-container">
          {mentors.map((m) => (
            <div key={m.sno} className="mentor-card">
              <h3>{m.facultyname}</h3>
              <p><strong>Specialization:</strong> {m.specialization}</p>
              <p><strong>Email:</strong> {m.Email}</p>
              <p><strong>Designation:</strong> {m.designation}</p>
              <button onClick={() => setProjectData({ ...projectData, mentor_id: m.sno })}>
                Request Mentor
              </button>
            </div>
          ))}
        </div>
      )}

      {/* PROJECT TAB */}
      {activeTab === "project" && (
        <div className="project-form project-vertical">
          <h3>Submit Project Idea</h3>
          <form onSubmit={handleProjectSubmit}>
            <label>Mentor:</label>
            <select
              name="mentor_id"
              value={projectData.mentor_id}
              onChange={handleProjectChange}
              required
            >
              <option value="">Select Mentor</option>
              {mentors.map((m) => (
                <option key={m.sno} value={m.sno}>
                  {m.facultyname} ({m.specialization})
                </option>
              ))}
            </select>

            <label>Project Title:</label>
            <input
              type="text"
              name="project_title"
              value={projectData.project_title}
              onChange={handleProjectChange}
              required
            />

            <label>Domain:</label>
            <input
              type="text"
              name="domain"
              value={projectData.domain}
              onChange={handleProjectChange}
            />

            <label>Time Required:</label>
            <input
              type="text"
              name="time_required"
              value={projectData.time_required}
              onChange={handleProjectChange}
            />

            <label>Skills Required:</label>
            <input
              type="text"
              name="skills_required"
              value={projectData.skills_required}
              onChange={handleProjectChange}
            />

            <label>Project Overview:</label>
            <textarea
              name="description"
              value={projectData.description}
              onChange={handleProjectChange}
              rows="4"
            ></textarea>

            <button type="submit">Submit Project</button>
          </form>
        </div>
      )}
    </div>
  );
}
